import{_ as e,o as l,c as a,a2 as s}from"./chunks/framework.Pywvta2k.js";const h=JSON.parse('{"title":"八宫筮法与中医诊断","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/08-京氏易八宫/02-八宫筮法与中医诊断.md","filePath":"tcm-data/09-医易同源/08-京氏易八宫/02-八宫筮法与中医诊断.md","lastUpdated":1781084559000}'),n={name:"tcm-data/09-医易同源/08-京氏易八宫/02-八宫筮法与中医诊断.md"};function d(r,t,o,i,g,f){return l(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="八宫筮法与中医诊断" tabindex="-1">八宫筮法与中医诊断 <a class="header-anchor" href="#八宫筮法与中医诊断" aria-label="Permalink to &quot;八宫筮法与中医诊断&quot;">​</a></h1><blockquote><p>京氏易的&quot;世应飞伏&quot;在辨证中的运用 从临床角度来看&quot;卦象断病&quot;</p></blockquote><hr><h2 id="一、世应——病位与病证的对应" tabindex="-1">一、世应——病位与病证的对应 <a class="header-anchor" href="#一、世应——病位与病证的对应" aria-label="Permalink to &quot;一、世应——病位与病证的对应&quot;">​</a></h2><p>京房八宫每卦都有&quot;世爻&quot;和&quot;应爻&quot;：</p><table tabindex="0"><thead><tr><th style="text-align:left;">宫</th><th style="text-align:left;">世位</th><th style="text-align:left;">病位对应</th><th style="text-align:left;">世爻含义</th></tr></thead><tbody><tr><td style="text-align:left;">八纯（本宫）</td><td style="text-align:left;">上爻世</td><td style="text-align:left;">久病、先天、老病</td><td style="text-align:left;">病根最深</td></tr><tr><td style="text-align:left;">一世</td><td style="text-align:left;">初爻世</td><td style="text-align:left;">新病、表证</td><td style="text-align:left;">病在皮毛经络</td></tr><tr><td style="text-align:left;">二世</td><td style="text-align:left;">二爻世</td><td style="text-align:left;">病在肌肉</td><td style="text-align:left;">脾胃之病</td></tr><tr><td style="text-align:left;">三世</td><td style="text-align:left;">三爻世</td><td style="text-align:left;">病在脏腑</td><td style="text-align:left;">五脏之病</td></tr><tr><td style="text-align:left;">四世</td><td style="text-align:left;">四爻世</td><td style="text-align:left;">病在骨髓</td><td style="text-align:left;">深重难愈</td></tr><tr><td style="text-align:left;">五世</td><td style="text-align:left;">五爻世</td><td style="text-align:left;">病在神明</td><td style="text-align:left;">精神之病</td></tr><tr><td style="text-align:left;">游魂</td><td style="text-align:left;">四爻游魂</td><td style="text-align:left;">游走不定</td><td style="text-align:left;">痛无定处</td></tr><tr><td style="text-align:left;">归魂</td><td style="text-align:left;">三爻归魂</td><td style="text-align:left;">回归本位</td><td style="text-align:left;">恢复期</td></tr></tbody></table><p><strong>临床用法</strong>：</p><ul><li>多用于<strong>疑难病诊断</strong>——当常规辨证无效时，可参考世应断病位</li></ul><hr><h2 id="二、飞伏——隐证与显证" tabindex="-1">二、飞伏——隐证与显证 <a class="header-anchor" href="#二、飞伏——隐证与显证" aria-label="Permalink to &quot;二、飞伏——隐证与显证&quot;">​</a></h2><p><strong>飞</strong> = 显现的卦象（表面症状） <strong>伏</strong> = 隐藏的卦象（根本病机）</p><h3 id="飞伏辨证法" tabindex="-1">飞伏辨证法 <a class="header-anchor" href="#飞伏辨证法" aria-label="Permalink to &quot;飞伏辨证法&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">飞（表面）</th><th style="text-align:left;">伏（根本）</th><th style="text-align:left;">临床意义</th></tr></thead><tbody><tr><td style="text-align:left;">离火（上热）</td><td style="text-align:left;">坎水（下寒）</td><td style="text-align:left;"><strong>上热下寒</strong>（普光·普明）</td></tr><tr><td style="text-align:left;">震木（肝郁）</td><td style="text-align:left;">坤土（脾虚）</td><td style="text-align:left;"><strong>木郁克土</strong></td></tr><tr><td style="text-align:left;">兑金（肺热）</td><td style="text-align:left;">艮土（胃寒）</td><td style="text-align:left;"><strong>上热中寒</strong></td></tr><tr><td style="text-align:left;">巽风（疏泄）</td><td style="text-align:left;">坎水（肾封藏）</td><td style="text-align:left;"><strong>疏泄太过→肾不藏精</strong></td></tr></tbody></table><p><strong>普光的飞伏辨证</strong>：</p><ul><li><strong>飞（显）</strong>：离宫未济䷿——口渴、前胸出汗、血压高（上热）</li><li><strong>伏（藏）</strong>：坎宫坎䷜——腰凉、脚冷（下寒）</li></ul><p><strong>治法</strong>：见飞（上热）不能治飞——因为飞是表面的，伏才是根本。</p><ul><li>如果见飞治飞（用清热药）→ 使伏更寒 → 上热更重</li><li>正确的治法：<strong>治伏调飞</strong> → 温坎水 → 离火自降</li></ul><hr><h2 id="三、六爻与人体对应" tabindex="-1">三、六爻与人体对应 <a class="header-anchor" href="#三、六爻与人体对应" aria-label="Permalink to &quot;三、六爻与人体对应&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">爻位</th><th style="text-align:left;">人体部位</th><th style="text-align:left;">普光症状</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>上爻</strong>（天）</td><td style="text-align:left;">头·巅顶</td><td style="text-align:left;">头顶疤近百会、头发花白</td></tr><tr><td style="text-align:left;"><strong>五爻</strong>（天）</td><td style="text-align:left;">面·目·鼻</td><td style="text-align:left;">面色暗沉、目干涩、鼻疮</td></tr><tr><td style="text-align:left;"><strong>四爻</strong>（人）</td><td style="text-align:left;">胸·背</td><td style="text-align:left;">前胸出汗多（<strong>关键</strong>）</td></tr><tr><td style="text-align:left;"><strong>三爻</strong>（人）</td><td style="text-align:left;">腹·胃</td><td style="text-align:left;">腰部赘肉（<strong>关键</strong>）</td></tr><tr><td style="text-align:left;"><strong>二爻</strong>（地）</td><td style="text-align:left;">腰·少腹</td><td style="text-align:left;">腰凉（<strong>核心</strong>）</td></tr><tr><td style="text-align:left;"><strong>初爻</strong>（地）</td><td style="text-align:left;">足·胫</td><td style="text-align:left;">脚后跟裂、脚气</td></tr></tbody></table><p><strong>普光六爻诊断</strong>：</p><ul><li>上焦（四·五·上）= 离火浮越（前胸出汗+口渴+血压高）→ <strong>三爻阳盛</strong></li><li>下焦（初·二·三）= 坎水寒（腰凉+脚冷）→ <strong>二爻阴盛</strong></li><li><strong>关键在第三爻</strong>（人位·腹）：腰凉 + 腹部赘肉 → 中焦枢轴不转</li></ul><hr><h2 id="四、用于普光的完整筮法诊断" tabindex="-1">四、用于普光的完整筮法诊断 <a class="header-anchor" href="#四、用于普光的完整筮法诊断" aria-label="Permalink to &quot;四、用于普光的完整筮法诊断&quot;">​</a></h2><h3 id="得卦-未济䷿-→-既济䷾" tabindex="-1">得卦：未济䷿ → 既济䷾ <a class="header-anchor" href="#得卦-未济䷿-→-既济䷾" aria-label="Permalink to &quot;得卦：未济䷿ → 既济䷾&quot;">​</a></h3><p><strong>未济䷿</strong>（当前状态）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上卦：离☲（火）→ 相火不降 → 前胸出汗+口渴+血压高</span></span>
<span class="line"><span>下卦：坎☵（水）→ 肾水寒 → 腰凉+脚冷</span></span></code></pre></div><p><strong>既济䷾</strong>（治疗目标）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上卦：坎☵（水）→ 水在上 → 津液能上达 → 口不渴</span></span>
<span class="line"><span>下卦：离☲（火）→ 火在下 → 下焦温暖 → 腰不凉</span></span></code></pre></div><p><strong>如何从未济到既济</strong>：</p><ul><li>普光方中的<strong>牛膝</strong>引火下行 = 从未济的&quot;火在上&quot;→ 既济的&quot;火在下&quot;</li><li>普光方中的<strong>附子</strong>温肾水 = 从未济的&quot;水在下&quot;→ 既济的&quot;水润上&quot;</li></ul><hr><h2 id="五、小结" tabindex="-1">五、小结 <a class="header-anchor" href="#五、小结" aria-label="Permalink to &quot;五、小结&quot;">​</a></h2><p>八宫筮法用于临床的要点：</p><blockquote><p><strong>1. 见到&quot;飞&quot;（表面症状），不要治&quot;飞&quot;——要治&quot;伏&quot;（根本病机）。</strong><strong>2. 上热下寒 = 未济䷿ → 目标是既济䷾。</strong><strong>3. 八宫定位可以精准判断病位（初爻=足、二爻=腰、三爻=腹……）。</strong><strong>4. 世应判断病程长短。</strong><strong>5. 归魂=恢复期、预后良好。</strong></p></blockquote><p>医学层面的京氏易应用已全部涵盖于此。</p>`,36)])])}const y=e(n,[["render",d]]);export{h as __pageData,y as default};
